define("tiny_justify/commands",["core/str"],function(Str){"use strict";const COMMAND_ALIGNJUSTIFY="alignjustify",ICON_SVG='<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 16 16"><path fill-rule="evenodd" d="M2 12.5a.5.5 0 0 1 .5-.5h11a.5.5 0 0 1 0 1h-11a.5.5 0 0 1-.5-.5z"/><path fill-rule="evenodd" d="M2 9.5a.5.5 0 0 1 .5-.5h11a.5.5 0 0 1 0 1h-11a.5.5 0 0 1-.5-.5z"/><path fill-rule="evenodd" d="M2 6.5a.5.5 0 0 1 .5-.5h11a.5.5 0 0 1 0 1h-11a.5.5 0 0 1-.5-.5z"/><path fill-rule="evenodd" d="M2 3.5a.5.5 0 0 1 .5-.5h11a.5.5 0 0 1 0 1h-11a.5.5 0 0 1-.5-.5z"/></svg>',ICON_NAME="tiny_justify_icon";const getSetup=async()=>{const tooltip=await Str.get_string("alignjustify","tiny_justify"),menutext=await Str.get_string("alignjustifymenu","tiny_justify"),onAction=editor=>()=>editor.execCommand("JustifyFull"),onSetup=editor=>api=>{editor.on("NodeChange",()=>{api.setActive(editor.queryCommandState("JustifyFull"))})};return editor=>{editor.ui.registry.addIcon(ICON_NAME,ICON_SVG),editor.ui.registry.addToggleButton(COMMAND_ALIGNJUSTIFY,{tooltip:tooltip,icon:ICON_NAME,onAction:onAction(editor),onSetup:onSetup(editor)}),editor.ui.registry.addToggleMenuItem(COMMAND_ALIGNJUSTIFY,{text:menutext,icon:ICON_NAME,onAction:onAction(editor),onSetup:onSetup(editor)})}};return{COMMAND_ALIGNJUSTIFY:COMMAND_ALIGNJUSTIFY,getSetup:getSetup}});
